  ('police-8b7f1efc-moex-00518', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '有關警察任務、警察業務和警察勤務三者之間的邏輯關係之敘述，下列何者正確？', '["警察勤務與警察任務相互間具有「體用關係」，警察勤務為體，警察任務為用", "警察業務的完成須賴警察勤務的執行", "警察任務是警察勤務具體化的結果", "警察任務是警察業務具體化的結果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
