  ('police-8b7f1efc-moex-00525', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依偶發性及緊急性集會遊行處理原則之規定，下列敘述何者正確？', '["緊急性集會、遊行，指因特殊原因未經召集而自發聚集，且事實上無發起人或負責人之集會、遊行", "偶發性集會、遊行，指因事起倉卒，且非即刻舉行無法達其目的之集會、遊行", "緊急性集會、遊行之申請，主管機關應於收受申請書即時核定，並以書面通知負責人", "偶發性集會、遊行，得於依集會遊行法第6條規定公告之地區週邊範圍舉行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
